import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Project-Based Track","description":"Build a CLI coding agent from scratch, one feature at a time","frontmatter":{"title":"Project-Based Track","description":"Build a CLI coding agent from scratch, one feature at a time"},"headers":[],"relativePath":"learn/project/index.md","filePath":"learn/project/index.md"}'),n={name:"learn/project/index.md"};function o(l,t,s,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="project-based-track" tabindex="-1">Project-Based Track <a class="header-anchor" href="#project-based-track" aria-label="Permalink to &quot;Project-Based Track&quot;">​</a></h1><p>Build a fully functional CLI coding agent in Rust, chapter by chapter. Each chapter adds a new capability to your agent — by the end, you&#39;ll have built something comparable to tools like Claude Code and OpenCode.</p><p>This track is ideal if you learn best by doing. Every concept is introduced in the context of a real feature you&#39;re building. You&#39;ll start with a simple REPL and finish with a production-ready agent.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Build a working CLI coding agent from scratch in Rust</li><li>Understand the architecture of modern AI coding assistants</li><li>Implement core capabilities: tool use, streaming, TUI, and more</li><li>Learn Rust idioms through practical, incremental development</li><li>Ship a polished, extensible binary</li></ul><h2 id="chapters" tabindex="-1">Chapters <a class="header-anchor" href="#chapters" aria-label="Permalink to &quot;Chapters&quot;">​</a></h2><ol><li><a href="/project/01-hello-rust-cli/">Hello, Rust CLI</a> — Your first Rust binary and REPL</li><li><a href="/project/02-first-llm-call/">First LLM Call</a> — Connecting to the Anthropic API</li><li><a href="/project/03-the-agentic-loop/">The Agentic Loop</a> — The core loop that makes it an agent</li><li><a href="/project/04-building-a-tool-system/">Building a Tool System</a> — Extensible tool architecture</li><li><a href="/project/05-file-operations-tools/">File Operations Tools</a> — Read, write, and edit files</li><li><a href="/project/06-shell-execution/">Shell Execution</a> — Running commands safely</li><li><a href="/project/07-streaming-responses/">Streaming Responses</a> — Real-time token streaming</li><li><a href="/project/08-terminal-ui-with-ratatui/">Terminal UI with Ratatui</a> — Beautiful terminal interface</li><li><a href="/project/09-conversation-context-management/">Conversation Context Management</a> — Managing the context window</li><li><a href="/project/10-search-and-code-intelligence/">Search and Code Intelligence</a> — Grep, glob, and tree-sitter</li><li><a href="/project/11-git-integration/">Git Integration</a> — Version control as a safety net</li><li><a href="/project/12-permission-and-safety/">Permission and Safety</a> — Keeping the agent safe</li><li><a href="/project/13-multi-provider-support/">Multi-Provider Support</a> — Anthropic, OpenAI, Ollama</li><li><a href="/project/14-extensibility-and-plugins/">Extensibility and Plugins</a> — MCP, hooks, and plugins</li><li><a href="/project/15-production-polish/">Production Polish</a> — Shipping a real tool</li></ol><h2 id="cross-reference-linear-track" tabindex="-1">Cross-Reference: Linear Track <a class="header-anchor" href="#cross-reference-linear-track" aria-label="Permalink to &quot;Cross-Reference: Linear Track&quot;">​</a></h2><p>Each project chapter has a corresponding linear track chapter that covers the same concepts from a theory-first perspective.</p><table tabindex="0"><thead><tr><th>Project Chapter</th><th>Linear Chapter</th></tr></thead><tbody><tr><td>1. Hello, Rust CLI</td><td>2. Rust for Python Developers</td></tr><tr><td>2. First LLM Call</td><td>3. Understanding LLMs</td></tr><tr><td>3. The Agentic Loop</td><td>4. Anatomy of an Agentic Loop</td></tr><tr><td>4. Building a Tool System</td><td>5. Tool Systems Deep Dive</td></tr><tr><td>5. File Operations Tools</td><td>6. File System Operations</td></tr><tr><td>6. Shell Execution</td><td>7. Process Management and Shell</td></tr><tr><td>7. Streaming Responses</td><td>8. Streaming and Realtime</td></tr><tr><td>8. Terminal UI with Ratatui</td><td>9. Terminal User Interfaces</td></tr><tr><td>9. Conversation Context Management</td><td>10. Conversation State Machines</td></tr><tr><td>10. Search and Code Intelligence</td><td>11. Code Intelligence</td></tr><tr><td>11. Git Integration</td><td>12. Version Control Integration</td></tr><tr><td>12. Permission and Safety</td><td>13. Safety and Permissions</td></tr><tr><td>13. Multi-Provider Support</td><td>14. Provider Abstraction</td></tr><tr><td>14. Extensibility and Plugins</td><td>15. Extensibility Patterns</td></tr><tr><td>15. Production Polish</td><td>16–18. Testing, Packaging, Case Study</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Basic programming experience (Python is perfect)</li><li>A terminal and text editor</li><li>Curiosity about how AI coding tools work</li></ul>',12)])])}const g=e(n,[["render",o]]);export{u as __pageData,g as default};
